1789	### 5.7 Submissions
1790	
1791	**`POST /applications/:id/submissions`**
1792	```ts
1793	interface Req { videos: { platform: Platform; url: string }[]; cover_note?: string; }
1794	interface Res { submission_id: string; }

1	// Custom JWT helper for Marketify edge functions.
2	//
3	// Contract: signJwt({ sub, app_role, session_id }, { ttlSeconds? }) -> compact JWT.
4	//           verifyJwt(token) -> parsed claims or throws.
5	// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
6	// Secret: MARKETIFY_JWT_SECRET env var. Must match the Supabase project's
7	//         PostgREST jwt_secret so RLS sees the token as valid.
8	// Claims: `role` is the Postgres role PostgREST switches into ("authenticated"
9	//         for all logged-in users). The app-level role (creator | lister) lives
10	//         in `app_role` so it doesn't collide with PostgREST's role-switching
11	//         behavior. RLS policies read `sub` and `app_role` via `auth.jwt()`.
12	//         `session_id` feeds the denylist lookup in §15c.
13	// Auth:   no inbound auth requirement — this module is a building block.
14	
15	export type AppRole = "creator" | "lister";
16	
17	export interface JwtClaims {
18	  sub: string;
19	  role: "authenticated";
20	  app_role: AppRole;
21	  session_id: string;
22	  iat: number;
23	  exp: number;
24	}
25	
26	export interface SignInput {
27	  sub: string;
28	  app_role: AppRole;
29	  session_id: string;
30	}
31	
32	export interface SignOptions {
33	  ttlSeconds?: number;
34	}
35	
36	const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
37	const encoder = new TextEncoder();
38	const decoder = new TextDecoder();
39	
40	function readSecret(): string {
41	  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
42	  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
43	  return s;
44	}
45	
46	function base64UrlEncode(bytes: Uint8Array): string {
47	  let s = "";
48	  for (const b of bytes) s += String.fromCharCode(b);
49	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
50	}
51	
52	function base64UrlDecode(input: string): Uint8Array {
53	  const rem = input.length % 4;
54	  const b64 = (rem === 0 ? input : input + "=".repeat(4 - rem))
55	    .replaceAll("-", "+")
56	    .replaceAll("_", "/");
57	  let raw: string;
58	  try {
59	    raw = atob(b64);
60	  } catch {
61	    throw new Error("Malformed JWT");
62	  }
63	  const out = new Uint8Array(raw.length);
64	  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
65	  return out;
66	}
67	
68	async function importKey(
69	  secret: string,
70	  usages: KeyUsage[],
71	): Promise<CryptoKey> {
72	  return await crypto.subtle.importKey(
73	    "raw",
74	    encoder.encode(secret),
75	    { name: "HMAC", hash: "SHA-256" },
76	    false,
77	    usages,
78	  );
79	}
80	
81	export async function signJwt(
82	  input: SignInput,
83	  options: SignOptions = {},
84	): Promise<string> {
85	  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
86	  if (!Number.isFinite(ttl) || ttl <= 0) {
87	    throw new Error("ttlSeconds must be a positive finite number");
88	  }
89	  if (input.app_role !== "creator" && input.app_role !== "lister") {
90	    throw new Error("app_role must be 'creator' or 'lister'");
91	  }
92	
93	  const now = Math.floor(Date.now() / 1000);
94	  const payload: JwtClaims = {
95	    sub: input.sub,
96	    role: "authenticated",
97	    app_role: input.app_role,
98	    session_id: input.session_id,
99	    iat: now,
100	    exp: now + ttl,
101	  };
102	
103	  const headerB64 = base64UrlEncode(
104	    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
105	  );
106	  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
107	  const signingInput = `${headerB64}.${payloadB64}`;
108	
109	  const key = await importKey(readSecret(), ["sign"]);
110	  const sig = await crypto.subtle.sign(
111	    "HMAC",
112	    key,
113	    encoder.encode(signingInput),
114	  );
115	  const sigB64 = base64UrlEncode(new Uint8Array(sig));
116	
117	  return `${signingInput}.${sigB64}`;
118	}
119	
120	export async function verifyJwt(token: string): Promise<JwtClaims> {
121	  const parts = token.split(".");
122	  if (parts.length !== 3) throw new Error("Malformed JWT");
123	  const [headerB64, payloadB64, sigB64] = parts;
124	
125	  let header: { alg?: string };
126	  try {
127	    header = JSON.parse(decoder.decode(base64UrlDecode(headerB64)));
128	  } catch {
129	    throw new Error("Malformed JWT");
130	  }
131	  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");
132	
133	  const key = await importKey(readSecret(), ["verify"]);
134	  const ok = await crypto.subtle.verify(
135	    "HMAC",
136	    key,
137	    base64UrlDecode(sigB64),
138	    encoder.encode(`${headerB64}.${payloadB64}`),
139	  );
140	  if (!ok) throw new Error("Bad signature");
141	
142	  let payload: Partial<JwtClaims>;
143	  try {
144	    payload = JSON.parse(decoder.decode(base64UrlDecode(payloadB64)));
145	  } catch {
146	    throw new Error("Malformed JWT");
147	  }
148	
149	  if (
150	    typeof payload.sub !== "string" || payload.sub.length === 0 ||
151	    payload.role !== "authenticated" ||
152	    (payload.app_role !== "creator" && payload.app_role !== "lister") ||
153	    typeof payload.session_id !== "string" ||
154	    payload.session_id.length === 0 ||
155	    typeof payload.iat !== "number" ||
156	    typeof payload.exp !== "number"
157	  ) {
158	    throw new Error("JWT missing required claims");
159	  }
160	
161	  const now = Math.floor(Date.now() / 1000);
162	  if (payload.exp <= now) throw new Error("JWT expired");
163	  if (payload.iat > now + 60) throw new Error("JWT iat in the future");
164	
165	  return payload as JwtClaims;
166	}
